# Identify a pattern in a text string and then identify the indices where it matches

text = """"""
pattern = "GAACGCTGA"

# Matching indices
count_list = []
def match_index(text, pattern):
    for i in range(len(text) - len(pattern)+1):
        if text[i:i+len(pattern)] == pattern:
            count_list.append(i)
    return count_list

result = match_index(text, pattern)
print("Patterns broken by space :-) :", *result)
